import{_ as e,o as a,c as b,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"“道士”","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/“道士”.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/“道士”.md"}'),s={name:"4.资源分区/1.血统与训练/6.一次性血统/“道士”.md"};function o(d,p,l,_,i,c){return a(),b("div",null,[...p[0]||(p[0]=[r("h1",{id:"道士",tabindex:"-1"},[t("“道士” "),r("a",{class:"header-anchor",href:"#道士","aria-label":'Permalink to "“道士”"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),n('<h1 id="道士-1" tabindex="-1">“道士” <a class="header-anchor" href="#道士-1" aria-label="Permalink to &quot;“道士”&quot;">​</a></h1><p>“道士”</p><p>“道士”<br> 一次性血统<br> 价格：C+1200<br> 名为道士，实则只是看起来像是道士的某种似是非是的迷信世界观下产物，也可以认为是速成道士，一次性道士，或者是道士复制人集团。<br> 虽然这么说，但当道士们整齐划一的释放雷法的时候，即使是强大的妖兽也会瞬间爆发四散，绝对不能因为单纯的数量而小瞧他们。</p><p>道法自然：购买该血统后，你获得4点可自由分配的点数，进行技能树下的技艺购买，每额外支付1C+1000分可以增加2点分配点数。</p><p>“道士”技能树</p><p>帧气<br> 价格：2<br> 描述：某种修真系强化相关的能量，在不同的世界中可能被称之为灵气、真气、道力，是作为本世界观下道士自然而然拥有的独特能量。<br> 效果：开启帧气能量池，等同规则书内帧气，不占用改造位，额外获得一种新的用法-支付2点帧气，在使用一次罡雷咒或绝崖灵动法的攻击/服用烙色虎公丹时支付2点帧气，使攻击/防御增加3点，对应能量加值。<br> 没有“帧气”的单位无法从“道士”的技能中获得好处，但可以正常使用九浓露火炉。</p><p>烙色虎公丹<br> 价格：2<br> 描述：你学会了制作某种刻满细小文字的晦金丹药的方法。<br> “火药味，吞下后衣袍鼓胀，腰背弓起，仿佛猛虎上身，力大如牛，刀枪不入，水火不侵。”<br> 效果：以移动动作+花招动作服用随身携带的任意药物类消耗品（因此建议提前将药物含在嘴里，否则你可能需要花招动作以上的动作服用药物），你立刻获得6点天生防御以及基于天生防御的1dr/-与1点全能量抗力，视觉上你的体积还会增大1点。<br> 这是一个持续一场景的效果，重复使用不叠加。</p><p>罡雷咒<br> 价格：2<br> 描述：你学会了制作和使用写着复杂文字的黄符的方法，需要帧气才能激发（注意，必须是帧气，同读音的真气是没有任何作用的）。<br> “触摸指尖会有酥麻感，掐诀激发，释放可击毁木质承重梁的罡雷。”</p><p>效果：你获得了一种新的攻击模式，以风度+学识+专业：外法+辅助专业：凝神（专注）进行攻击，武器伤害：3L，造成雷电能量伤害，射程为10米，可以同时攻击扇形范围内的所有敌人。</p><p>使用这种方式进行攻击，你必须实先通过一个不需要前置条件的智力+学识：外法（专业）进行制作符纸，制作时间为15分钟，难度DC为1，一次制作的量取决于黄纸数量，每次攻击消费1张制作好的符纸。</p><p>绝崖灵动法<br> 价格：2<br> 描述：不运火而火自炼，无为无心巧安排，神功灵动寻患处……<br> “念咒驱剑，生伏虎巨力斩敌。”<br> 效果：当你持用任意武器时，可以以自由动作默念法咒，并在接下来的战斗中以34DP+4附加代替你的正常攻击模式（必须是近战武器），这种攻击还具有【破甲】【高速】【威猛】的效果，需在获得该技艺时自行分配破甲与威猛点数，但合计不能超过7点。</p><p>九浓露火炉<br> 描述：巴掌大的小炉，表面刻有巨大的“火”字。<br> “可放出从火炉灰。如同一团活的烟火，存在自我意识，可撞破房屋，点燃物品。”<br> 你可以通过一个不需要前置条件的智力+学识：外法（专业）制造一尊九浓露火炉（同时只可存在一尊），制作时间为15分钟，难度DC为0，只有火炉存在的时候你才能召唤从火炉灰，从火炉灰的召唤和驱散为自由动作，当从火炉灰被击破时火炉也会视为损坏，次日才能重新制作。</p><p>从火炉灰<br> 价格：4<br> 体积：1-10（数据影响上始终视为5）<br> 力11/敏9/耐11<br> 感9/决9/智6<br> 风6/操6/沉6<br> 武技8级-天生武器8<br> 学识8级-武学掌握8<br> 调查5级-侦查5级<br> 运动-专注-生存5级-反射/意志/强韧5级<br> 其他技能1级。<br> 生命值：11+5+5*2=26<br> 移动速度：28米<br> 基础防御：9<br> 攻击DP＝力量11+武技8+专业8+辅助专业8+武器伤害7＝11+8+8+8=42DP+4附加【9加骰】</p><p>虚体生命：从火炉灰视为虚体，即使生命值被严重填满也不会昏迷</p><p>天生武器：视为全身天生武器具有【法破】【造成火焰伤害】【武器伤害7L】【9加骰】</p><p>被造物：从火炉灰听从具有帧气单位的命令，且优先听从制造者的命令，其次听从持有浓露火炉单位的命令，因从火炉灰可以自由行动，具有完整的轮次，因此只需要自由动作就可以对它下达命令，这同时视为具有D级免疫心灵影响的效果。</p><p>专属消耗品<br> “道士”才能使用的专属消耗品，非“道士”无法从中获得好处。</p><p>通用黄纸（10分）<br> 黄纸，朱砂，一系列制作符纸所需的物品，通常只要购买就视为你总是拥有可以无限制作相关符纸的材料，不占用负重与空间。<br> （精品：购买时额外消耗250分，将其替换为精品黄纸，永久在使用符纸进行攻击检定时获得1DP加值。）</p><p>通用药材<br> 乱七八糟的药材，通常只要购买就视为你总是拥有可以无限制作相关丹药的材料，作为药物消耗品吞服时不产生效果，也不占用负重与空间。<br> （变体：百年药材，购买时额外消费500分，效果同无支线消耗品伤药，每次购买足够使用9次。）</p><p>专属专长<br> “道士”才能进行兑换与使用的专长能力。</p><p>五雷正法（1-2）<br> 2级：你在使用罡雷咒进行攻击时，可以同时消费5张符纸，使本次攻击获得【连射】【法破】的效果。</p><p>九转回魂丹（2，3）<br> 2级：你在使用百年药材进行制作丹药时，可以选择单独制作一枚九转回魂丹而不是烙色虎公丹，服用者会立刻获得快速医疗2（医疗点数24）。你每日只能制作一次九转回魂丹，且效果也只会持续一日。</p><p>3级：现在九转回魂丹还会提供1点异常状态医疗（医疗点数24），服用者当日不会因生命值被严重伤害填满而昏迷，其他限制不变。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',25)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
